const payload = $json.payload || {};
const recommendation = payload.recommendation || null;
if (!recommendation || !recommendation.recommended_location_id || !$json.picking_context || !$json.picking_context.location_id) {
  return [];
}
const ticketText = [
  'Automatisch erzeugter Nachschubauftrag aus dem Voice-Exception-Pfad.',
  payload.text ? `Meldung: ${payload.text}` : '',
  recommendation.reason ? `Grund: ${recommendation.reason}` : '',
].filter(Boolean).join(' ');
return [{ json: {
  correlation_id: $json.correlation_id,
  picking_id: $json.picking_context.picking_id,
  product_id: $json.picking_context.product_id,
  location_id: $json.picking_context.location_id,
  recommended_location_id: recommendation.recommended_location_id,
  recommended_location: recommendation.recommended_location || '',
  quantity: recommendation.quantity || 1,
  reason: recommendation.reason || 'Automatische Nachschubanforderung nach Fehlmengen-Hinweis.',
  ticket_text: ticketText,
  requested_by_user_id: payload.requested_by_user_id || $json.picker.user_id || null,
  requested_by_name: $json.picker.name || '',
  log_message: `Nachschub fuer Picking ${$json.picking_context.picking_id} von ${recommendation.recommended_location || 'Alternativplatz'} nach Zielplatz ${$json.picking_context.location_id} angestossen.`,
} }];
